queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?customs a :Customs .
    ?customs p:CustomOfficerName ?customofficername .
    ?customs p:Airport ?airport_f .
    FILTER(STR(?airport_f) = "Gatwick")
    BIND(?customofficername AS ?o0)
  }
  UNION
  {
    ?immigration a :Immigration .
    ?immigration p:ImmigrationOfficerName ?immigrationofficername .
    ?immigration p:Airport ?airport_f .
    FILTER(STR(?airport_f) = "Gatwick")
    BIND(?immigrationofficername AS ?o0)
  }
}

